const handleSubmit = async (e) => {
  e.preventDefault();
  setLoading(true);
  setError('');

  try {
    if (tab === 'login') {
      const res = await login(form.email, form.password);

      // đźš¨ ACCOUNT DISABLED
      if (res.blocked) {
        setError(res.message);
        setLoading(false);
        return;
      }

      // SUCCESS LOGIN
      localStorage.setItem('token', res.token);
      setUser(res.user);

      navigate(res.user.role === 'admin' ? '/admin' : '/');
    } 
    else {
      const res = await register(
        form.fullName,
        form.email,
        form.password,
        form.phone
      );

      localStorage.setItem('token', res.token);
      setUser(res.user);

      navigate('/');
    }
  } catch (err) {
    setError(err.response?.data?.message || 'Something went wrong');
  } finally {
    setLoading(false);
  }
};
